import {
  useFetchUserInfo,
  useListTenantUser,
} from '@/hooks/user-setting-hooks';
import { UserOutlined } from '@ant-design/icons';
import {
  Button,
  Card,
  Divider,
  Form,
  Input,
  Modal,
  Space,
  Switch,
  message,
} from 'antd';
import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import AddingUserModal from './add-user-modal';
import { useAddUser } from './hooks';
import styles from './index.less';
import UserTable from './user-table';
const iconStyle = { fontSize: 20, color: '#1677ff' };
type FieldType = {
  id?: string;
  parentUserId?: string;
  nickname?: string;
  language?: string;
  email?: string;
  password?: string;
  isCreateKownledge?: boolean;
  color_schema?: string;
  timezone?: string;
  avatar?: string;
};
const UserSettingTeam = () => {
  const { data: userInfo } = useFetchUserInfo();
  const { t } = useTranslation();
  useListTenantUser();
  const {
    addingTenantModalVisible,
    hideAddingTenantModal,
    showAddingTenantModal,
    handleAddUserOk,
  } = useAddUser();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [confirmLoading, setConfirmLoading] = useState(false);
  const [emaillInputDisabled, setEmaillInputDisabled] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);
  const [userForm] = Form.useForm<FieldType>();

  let showInviteUserButton = false; // 控制是否显示邀请用户按钮
  if (userInfo.is_superuser || userInfo.is_create_kownledge) {
    showInviteUserButton = true;
  }
  const handleSaveUser = async () => {
    setConfirmLoading(true);
    let postData = userForm.getFieldsValue();
    postData.parentUserId = userInfo.id || '';
    const response = await fetch('/custom/user/save', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(postData),
    });
    setConfirmLoading(false);

    if (!response.ok) {
      message.error(t('setting.saveErrorAction'));
    } else {
      const data = await response.json();
      if (data.Result == 0) {
        message.error(data.Msg);
      } else {
        userForm.resetFields();
        setIsModalOpen(false);
        message.success(t('setting.saveSuccessAction'));
        // 👇 刷新用户列表
        setRefreshKey((prev) => prev + 1);
      }
    }
  };

  const onOpenEditModal = (record: any) => {
    setIsModalOpen(true);
    setEmaillInputDisabled(true);
    userForm.setFieldsValue({
      id: record.user_id,
      nickname: record.nickname,
      email: record.email,
      parentUserId: userInfo.id,
      isCreateKownledge: record.is_create_kownledge,
    });
  };

  return (
    <>
      <div className={styles.teamWrapper}>
        {/* <Card className={styles.teamCard}>
        <Flex align="center" justify={'space-between'}>
          <span>
            {userInfo.nickname} {t('setting.workspace')}
          </span>
          <Button type="primary" onClick={showAddingTenantModal}>
            <UserAddOutlined />
            {t('setting.invite')}
          </Button>
        </Flex>
      </Card> */}
        <Card
          title={
            <Space>
              <UserOutlined style={iconStyle} /> {t('setting.teamMembers')}
            </Space>
          }
          extra={
            <Space>
              {userInfo.is_superuser && (
                <Button
                  type="primary"
                  onClick={() => {
                    setEmaillInputDisabled(false);
                    setIsModalOpen(true);
                  }}
                >
                  {t('setting.addUser')}
                </Button>
              )}

              {userInfo.is_create_kownledge && (
                <Button type="default" onClick={showAddingTenantModal}>
                  {t('setting.invite')}
                </Button>
              )}
            </Space>
          }
          bordered={false}
        >
          <UserTable
            onOpenEditModal={onOpenEditModal}
            key={refreshKey}
          ></UserTable>
        </Card>
        {/* <Card
          title={
            <Space>
              <TeamOutlined style={iconStyle} /> {t('setting.joinedTeams')}
            </Space>
          }
          bordered={false}
        >
          <TenantTable></TenantTable>
        </Card> */}
        {addingTenantModalVisible && (
          <AddingUserModal
            visible
            hideModal={hideAddingTenantModal}
            onOk={handleAddUserOk}
          ></AddingUserModal>
        )}
      </div>

      <Modal
        title={t('setting.addUser')}
        confirmLoading={confirmLoading}
        open={isModalOpen}
        destroyOnClose={true}
        maskClosable={false}
        onOk={() => userForm.submit()}
        onCancel={() => {
          setIsModalOpen(false);
          setConfirmLoading(false);
        }}
      >
        <Form
          form={userForm}
          colon={false}
          name="userModel"
          layout="vertical"
          onFinish={handleSaveUser}
          style={{ width: '100%' }}
          autoComplete="off"
        >
          <Form.Item<FieldType>
            label="id"
            name="id"
            style={{ display: 'none' }}
          >
            <Input disabled={emaillInputDisabled} />
          </Form.Item>

          <Form.Item<FieldType>
            label={t('login.loginUserNameLabel')}
            name="email"
            rules={[
              {
                required: true,
                message: t('setting.loginusernameMessage'),
                whitespace: true,
              },
            ]}
          >
            <Input disabled={emaillInputDisabled} />
          </Form.Item>

          <Form.Item<FieldType>
            label={t('setting.username')}
            name="nickname"
            rules={[
              {
                required: true,
                message: t('setting.usernameMessage'),
                whitespace: true,
              },
            ]}
          >
            <Input />
          </Form.Item>
          <Form.Item<FieldType>
            label={t('setting.canCreateKnowledge')}
            name="isCreateKownledge"
            valuePropName="checked"
          >
            <Switch />
          </Form.Item>
          <Divider />
          <ul style={{ color: '#666', gap: '16px' }}>
            <li>
              {t('setting.emailDescription')}
              {t('setting.passwordAction')}
            </li>
          </ul>
        </Form>
      </Modal>
    </>
  );
};

export default UserSettingTeam;
