import {
  useFetchUserInfo,
  useListTenantUser,
} from '@/hooks/user-setting-hooks';
import { ITenantUser } from '@/interfaces/database/user-setting';
import { formatDate } from '@/utils/date';
import {
  DeleteOutlined,
  FormOutlined,
  InteractionOutlined,
} from '@ant-design/icons';
import type { TableProps } from 'antd';
import { Button, Popconfirm, Space, Table, Tag, Tooltip, message } from 'antd';
import { upperFirst } from 'lodash';
import { useTranslation } from 'react-i18next';
import { TenantRole } from '../constants';
import { useHandleDeleteUser } from './hooks';
const ColorMap = {
  [TenantRole.Normal]: 'green',
  [TenantRole.Invite]: 'orange',
  [TenantRole.Owner]: 'red',
};
// 定义 props 类型
interface ChildComponentProps {
  onOpenEditModal: (data: any) => void; // 接收父组件传递的方法
}
const UserTable: React.FC<ChildComponentProps> = ({ onOpenEditModal }) => {
  const { data: userInfo } = useFetchUserInfo();
  const { data, loading } = useListTenantUser();
  const { handleDeleteTenantUser } = useHandleDeleteUser();
  const { t } = useTranslation();
  const rePwd = async (user_id: string) => {
    const response = await fetch('/custom/user/rePwd', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ id: user_id }),
    });
    if (response.ok) {
      const data = await response.json();
      if (data.Result) {
        message.success(
          t('common.rePwd') + t('knowledgeDetails.runningStatus3'),
        );
      } else {
        message.error(t('common.rePwd') + t('knowledgeDetails.runningStatus4'));
      }
    } else {
      message.error(t('common.rePwd') + t('knowledgeDetails.runningStatus4'));
    }
  };

  const columns: TableProps<ITenantUser>['columns'] = [
    {
      title: t('common.name'),
      dataIndex: 'nickname',
      key: 'nickname',
    },
    {
      title: t('setting.email'),
      dataIndex: 'email',
      key: 'email',
    },
    {
      title: t('setting.role'),
      dataIndex: 'role',
      key: 'role',
      render(value, { role }) {
        return (
          <Tag color={ColorMap[role as keyof typeof ColorMap]}>
            {upperFirst(role)}
          </Tag>
        );
      },
    },
    {
      title: t('setting.updateDate'),
      dataIndex: 'update_date',
      key: 'update_date',
      render(value) {
        return formatDate(value);
      },
    },
    {
      title: t('common.action'),
      key: 'action',
      render: (_, record) => (
        <Space>
          <Tooltip title={t('common.delete')}>
            <Button
              type="text"
              onClick={handleDeleteTenantUser(userInfo.id, record.user_id)}
            >
              <DeleteOutlined size={20} />
            </Button>
          </Tooltip>

          {record.role === TenantRole.Normal && (
            <Tooltip title={t('setting.modify')}>
              <Button type="text" onClick={() => onOpenEditModal(record)}>
                <FormOutlined size={20} />
              </Button>
            </Tooltip>
          )}

          {record.role === TenantRole.Normal && (
            <Tooltip title={t('common.rePwd')}>
              <Popconfirm
                title={t('common.rePwdAction')}
                onConfirm={() => {
                  rePwd(record.user_id);
                }}
                okText={t('common.ok')}
                cancelText={t('common.cancel')}
              >
                <Button type="text">
                  <InteractionOutlined size={20} />
                </Button>
              </Popconfirm>
            </Tooltip>
          )}
        </Space>
      ),
    },
  ];

  return (
    <Table<ITenantUser>
      rowKey={'user_id'}
      columns={columns}
      dataSource={data}
      loading={loading}
      pagination={false}
    />
  );
};

export default UserTable;
